using Microsoft.UI.Xaml; using Microsoft.UI.Xaml.Controls;
namespace Parsis.AutoTrader.App.Pages;
public sealed partial class RiskPage:Page{private readonly AppState S=AppState.Current;public RiskPage(){InitializeComponent();RiskToggle.IsOn=S.Settings.Risk.UseRiskPercent;LotBox.Value=(double)S.Settings.Risk.FixedLot;RiskBox.Value=(double)S.Settings.Risk.RiskPercent;MaxBox.Value=S.Settings.Risk.MaxConcurrentTrades;BreakEvenToggle.IsOn=S.Settings.Risk.MoveStopToBreakEvenAtTp1;}private async void Save_Click(object sender,RoutedEventArgs e){S.Settings.Risk.UseRiskPercent=RiskToggle.IsOn;S.Settings.Risk.FixedLot=(decimal)LotBox.Value;S.Settings.Risk.RiskPercent=(decimal)RiskBox.Value;S.Settings.Risk.MaxConcurrentTrades=(int)MaxBox.Value;S.Settings.Risk.MoveStopToBreakEvenAtTp1=BreakEvenToggle.IsOn;await S.SettingsService.SaveAsync(S.Settings);}}
